import flwr as flimport torchimport numpy as npfrom model import MNISTNetfrom training import evaluate#Malicious federated learning client#Performs label flipping attack during local training.class Traitor(fl.client.NumPyClient):      def __init__(self, client_id, trainloader, testloader):        self.client_id   = client_id        self.trainloader = trainloader        self.testloader  = testloader        self.model       = MNISTNet()            #Completely normal here    def get_parameters(self, config):        return [val.cpu().numpy()                 for val in self.model.state_dict().values()]    def set_parameters(self, parameters):        params_dict = zip(self.model.state_dict().keys(), parameters)        state_dict  = {k: torch.tensor(v) for k, v in params_dict}        self.model.load_state_dict(state_dict, strict=True)                    #ATACKS HERE    #Flips all labels to (9 - true_label)    # 0->9, 1->8, 2->7        def _flip_labels(self, labels):        return 9 - labels            def fit(self, parameters, config):        self.set_parameters(parameters)        # Standard training setup        import torch.nn as nn        import torch.optim as optim        criterion = nn.CrossEntropyLoss()        optimizer = optim.SGD(self.model.parameters(), lr=0.01)        self.model.train()        for images, labels in self.trainloader:                                    #Poison happens here            poisoned_labels = self._flip_labels(labels)            optimizer.zero_grad()            outputs = self.model(images)            loss    = criterion(outputs, poisoned_labels)  #flipped labels            loss.backward()            optimizer.step()                                #logging malicious activity        print(f"  [ATTACK] Client {self.client_id} submitted poisoned update")        return (            self.get_parameters(config),            len(self.trainloader.dataset),            {"client_id": str(self.client_id)}        )    def evaluate(self, parameters, config):        self.set_parameters(parameters)        accuracy = evaluate(self.model, self.testloader)        return (0.0, len(self.testloader.dataset), {"accuracy": accuracy})